function ProductList({ products, initialQuery }: { products: Product[]; initialQuery: string }) {
  const [query, setQuery] = useState(initialQuery);
  const [filteredProducts, setFilteredProducts] = useState<Product[]>([]);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [selectedProductId, setSelectedProductId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isLoaded, setIsLoaded] = useState(false);
  const [isError, setIsError] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    setQuery(initialQuery);
  }, [initialQuery]);

  useEffect(() => {
    setFilteredProducts(products.filter((product) => product.name.includes(query)));
  }, [products, query]);

  useEffect(() => {
    setSelectedProduct(products.find((product) => product.id === selectedProductId) ?? null);
  }, [products, selectedProductId]);

  async function refresh() {
    setIsLoading(true);
    setIsLoaded(false);
    setIsError(false);
    try {
      await reloadProducts();
      setIsLoaded(true);
    } catch (err) {
      setIsError(true);
      setError(String(err));
    } finally {
      setIsLoading(false);
    }
  }

  return null;
}
